INSERT INTO sys_news (title, category, content, cover_url, views) VALUES
('关于开展2026年春季学期校园安全教育月的通知', '通知公告', '为进一步增强全校师生的安全意识，提高防范和应对各类安全风险的能力，学校决定于2026年4月开展“校园安全教育月”活动。本次活动将围绕消防安全、交通安全、网络安全、实验室安全及心理健康等主题，通过线上线下相结合的方式，开展形式多样的教育活动。希望广大师生积极参与，共同营造安全、和谐的校园环境。\n\n活动安排：\n1. 4月5日：校园消防演练\n2. 4月10日：防范电信诈骗专题讲座\n3. 4月15日：实验室安全规范培训\n4. 4月20日：大学生心理健康沙龙', 'https://images.unsplash.com/photo-1541339907198-e08756dedf3f?auto=format&fit=crop&w=600&q=80', 1250),
('警惕新型电信诈骗！近期多名大学生中招', '防骗预警', '近期，我市多所高校发生学生遭遇新型电信网络诈骗的案件。诈骗分子通常以“注销校园贷账户”、“淘宝客服理赔”、“公检法办案”等为由，诱导学生下载虚假APP、屏幕共享或转账汇款。保卫处提醒广大同学：\n1. 凡是自称公检法要求汇款的，都是诈骗！\n2. 凡是要求注销校园贷记录的，都是诈骗！\n3. 凡是索要验证码或要求屏幕共享的，都要高度警惕！\n如遇可疑情况，请立即拨打110或校内报警电话。', 'https://images.unsplash.com/photo-1563206767-5b18f218e8de?auto=format&fit=crop&w=600&q=80', 3420),
('实验室安全无小事，这些违规操作千万别做', '实验室安全', '实验室是学校教学和科研的重要场所，安全是重中之重。近日，某高校实验室因学生违规操作引发火灾，造成严重财产损失。为吸取教训，特整理以下常见违规操作，请大家引以为戒：\n1. 未穿戴防护装备（实验服、护目镜等）进入实验室。\n2. 实验过程中脱岗，导致反应失控未能及时发现。\n3. 随意混合化学试剂，引发剧烈反应或爆炸。\n4. 实验废液未按规定分类收集，直接倒入下水道。\n5. 实验结束后未关闭水、电、气和门窗。', 'https://images.unsplash.com/photo-1532094349884-543bc11b234d?auto=format&fit=crop&w=600&q=80', 890),
('春季传染病高发，校园防疫指南请收好', '健康卫生', '春季是流感、诺如病毒、水痘等传染病的高发季节。由于校园人员密集，传染病极易传播。为了同学们的身体健康，校医院发布以下防疫指南：\n1. 保持良好的个人卫生习惯，勤洗手，尤其是在饭前便后和外出归来。\n2. 保持宿舍、教室等室内环境的通风换气，每天至少通风2次，每次不少于30分钟。\n3. 注意饮食卫生，不吃生冷食物，不喝生水。\n4. 加强体育锻炼，保证充足睡眠，提高自身免疫力。\n5. 若出现发热、咳嗽、呕吐、腹泻等症状，应及时就医，并向辅导员报告。', 'https://images.unsplash.com/photo-1584036561566-baf8f5f1b144?auto=format&fit=crop&w=600&q=80', 2100);
